INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-01449', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關角膜基質層水腫（stromaledema）的敘述，下列何者錯誤？', '["常見配戴軟式隱形眼鏡者，因不當的使用導致角膜缺氧（cornealhypoxia）引起的", "如基質層水腫超過2～3%，病人就會抱怨視力下降，戴眼鏡視力模糊、會有光暈現象", "有角膜基質層水腫時，處理的方法為減少配戴的時間或更換透氧性（Dk）高的鏡片", "只要基質層水腫超過9%以上，角膜內皮層（endothelium）就會產生褶痕（folds）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01450', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡相關併發症的治療方式，下列何者不應該使用類固醇治療？', '["過敏性結膜炎（allergicconjunctivitis）", "巨乳頭性結膜炎（giantpapillaryconjunctivitis）", "急性眼部細菌性或黴菌感染", "角膜微囊性水腫（cornealmicrocysticedema）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01451', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列的隱形眼鏡配戴者，何者應儘可能避免跨夜配戴隱形眼鏡（overnight wear）的方式？①游泳選手', '["慢性眼瞼發炎", "重度乾眼症", "不明原因之角膜瘢痕", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01452', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一位配戴延長配戴型矽水膠隱形眼鏡（extended-wear silicone hydrogel lenses）的25歲男性來接受例行回 診，在裂隙燈檢查中你發現在鏡片後方有許多大小不一的透明點狀物在角膜上皮上，放大看發現這些點狀 物貌似被壓平的甜甜圈（flatteneddoughnut）；拿下隱形眼鏡後，部分點狀物仍黏在角膜上皮上，一部分隨 著眨眼被沖刷，在上皮上留下一個小凹（pit），不論是殘留的點狀物或是小凹皆可被螢光染劑染色，高倍 下看這些小凹呈現非反轉式照明（unreversedillumination），最符合的診斷為？', '["角膜上皮微囊（epithelialmicrocysts）", "黏液球（mucinballs）", "角膜上皮磨損（cornealabrasion）", "角膜變形（cornealwarpage）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01453', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡導致角膜上方弓形表皮破損（superiorepithelialarcuatelesions,SEALs），下列敘述何者錯誤？', '["多數病患摘下鏡片，傷口暴露後會感覺到劇烈疼痛", "較常見於使用高Dk材質或矽水膠隱形眼鏡者", "病灶大多位於角膜上半部且平行輪狀部", "與鏡片的材質和硬度，以及眼瞼太緊或眼皮摩擦有關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01454', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡引起的角膜新生血管的敘述，下列何者錯誤？', '["初期通常就會影響視力", "血管翳（pannus）分成發炎性（inflammatory）及退化性（degenerative）兩種", "以表淺層的新生血管最常見", "血管翳通常發生在角膜的上方"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01455', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關使用隱形眼鏡所產生的併發症，下列敘述何者錯誤？', '["黏液球是由淚水中的油脂及蛋白質組成，矽水膠隱形眼鏡常常戴過夜的人，會看到黏液球卡在角膜上皮", "隱形眼鏡造成的上角膜緣（輪部）角結膜炎（superiorlimbickeratoconjunctivitis），可能與角膜缺氧有關", "戴用軟式隱形眼鏡，眨眼不完全，會在下方角膜呈現上皮螢光染色", "乾眼症患者建議使用高含水的水膠隱形眼鏡，較為舒服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01456', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '王女士戴著有色裝飾性的隱形眼鏡出席派對，當晚戴著鏡片睡覺，翌日醒來，右眼感到劇痛、結膜布滿血 絲、甚至視力變得模糊，並有黏稠黃色分泌物，有關此狀況，下列選項何者正確？', '["鏡片缺角破損，應移除鏡片後在家休養", "有可能感染綠膿桿菌，應即時求診並進行微生物化驗以證實感染", "需用強力類固醇藥水治療，才得以挽回視力", "及時醫治後，大約一個月後才能再配戴任何隱形眼鏡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01457', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡引起的角膜炎，下列敘述何者錯誤？', '["可能為感染性或非感染性，初期皆應認定為感染性為治療方式", "早期症狀為異物感、想拔除隱形眼鏡，若拔除後症狀未改善，則很可能是感染性角膜炎", "細菌性角膜炎會有表皮潰爛、角膜水腫混濁、前房蓄膿等症狀", "微生物培養若為陰性則可排除感染之可能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01458', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者隱形眼鏡引起的併發症與缺氧無關？', '["輪部充血（limbalhyperemia）", "新生血管（neovascularization）", "内皮細胞多狀症（endothelialpolymegethism）", "角膜上方弓形表皮破損"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
